from beeai.memory import MemoryRetriever
from vex_sdk import VexListener

class MemoryDriftDetector(VexListener):
    def __init__(self):
        self.session_scores = {}

    def on_memory_retrieval(self, event):
        session_id = event.session_id
        scores = [doc.score for doc in event.documents]
        avg_score = sum(scores) / len(scores)

        if session_id not in self.session_scores:
            self.session_scores[session_id] = []
        self.session_scores[session_id].append(avg_score)

        if len(self.session_scores[session_id]) > 5:
            trend = np.mean(self.session_scores[session_id][-3:]) - np.mean(self.session_scores[session_id][:3])
            if trend < -0.1:
                self.vex.flag_issue('MEMORY_DRIFT', f'Score trend: {trend:.3f}')

