from beeai.tools import Tool
from beeai.llm import GraniteLLM

rewrite_llm = GraniteLLM(model='ibm/granite-3b')

class OptimizedRetriever:
    def __init__(self, retriever):
        self.retriever = retriever

    def retrieve(self, query, **kwargs):
        # Rewrite query for better retrieval
        rewrite_prompt = f"""
        Rewrite this query to maximize retrieval quality:
        Original: {query}
        Optimized:
        """

        rewritten = rewrite_llm.generate(rewrite_prompt, max_tokens=50)
        return self.retriever.retrieve(rewritten, **kwargs)

agent.retriever = OptimizedRetriever(agent.retriever)
